# DE 1751.  Wunstorf - Gümmerwald
#
let wl = path("d3.de.1750");

with detail = 3,
     railway = :first :double :cat:ac15 :nopax
{
    with link = "line.de.1751" {
        track(:ror, wl[:wun + 900m, :wun + 1100m] << 1ms << 1md);
        track(:ror,
                wl[:wun + 1099m, :wun + 1100m] << 1ms << 1md
            ..  wl[:gum.yw - 0.1dl, :gum.yw] << 1ms << 1.5md
        );
        track(:ror:lor :casing,
                wl[:gum.yw - 0.1dl, :gum.yw] << 1ms << 1.5md
            ..  wl[:gum.xw - 0.1dl, :gum.xw] >> 1ms >> 2md
        );
        track(:ror:lor,
                wl[:gum.xw - 0.1dl, :gum.xw] >> 1ms >> 2md
            ..  wl[:gum - 0.1dl, :gum] >> 1ms >> 1md
        );
    }
}

